mapper.select:
select event_instance_id, company_id, event_template_id, cover_image_url, event_at, event_end_at, source_type, source_department_ids, source_user_ids,
       participant_user_ids, status, notified_at, created_by, created_at, updated_at
from event_instances
where company_id = #{companyId,jdbcType=VARCHAR}
  and event_instance_id = #{eventInstanceId,jdbcType=VARCHAR}
limit 1

select event_instance_id, company_id, event_template_id, cover_image_url, event_at, event_end_at, source_type, source_department_ids, source_user_ids,
       participant_user_ids, status, notified_at, created_by, created_at, updated_at
from event_instances
where event_at >= #{windowStart,jdbcType=TIMESTAMP}
  and event_at <= #{windowEnd,jdbcType=TIMESTAMP}
  and notified_at is null
  and upper(coalesce(status, 'PUBLISHED')) = 'PUBLISHED'
order by event_at asc
limit #{limit}

mapper.update:
update event_instances
set notified_at = #{updatedAt,jdbcType=TIMESTAMP},
    updated_at = #{updatedAt,jdbcType=TIMESTAMP}
where event_instance_id = #{eventInstanceId,jdbcType=VARCHAR}
  and notified_at is null

UPDATE event_instances
SET status = #{status},
    updated_at = #{updatedAt}
WHERE company_id = #{companyId}
  AND event_instance_id = #{eventInstanceId}
